def most_common_word(s):
    if not s:
        return ''

    words = s.lower().split()
    word_count = {}

    for word in words:
        if word in word_count:
            word_count[word] += 1
        else:
            word_count[word] = 1

    max_count = max(word_count.values())
    most_common = [word for word, count in sorted(word_count.items()) if count == max_count]

    return most_common[-1]

# Edge case: multiple words with the same highest count
edge_case_1 = "apple banana apple orange banana"
print(most_common_word(edge_case_1))  # Output: 'banana'
